// ManagerProfile.js - قالب المدير (بدون QR حقيقي)
import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

export default function ManagerProfile() {
  // ==================== STATE MANAGEMENT ====================
  
  // المربع 1: الطاولات
  const [tables, setTables] = useState([]);
  const [newTableCount, setNewTableCount] = useState(1);
  const [selectedGroupForTable, setSelectedGroupForTable] = useState("");
  const [showQRPlaceholder, setShowQRPlaceholder] = useState(false);
  const [selectedTableForQR, setSelectedTableForQR] = useState(null);
  
  // المربع 2: المجموعات
  const [groups, setGroups] = useState([
    { id: 1, name: "المجموعة 1", tableIds: [], tableRange: { start: 1, end: 9 } }
  ]);
  const [newGroupName, setNewGroupName] = useState("");
  
  // المربع 3: الموظفين والربط
  const [employees, setEmployees] = useState([
    { id: 1, name: "يوسف", role: "موظف", groupId: 1, status: "active" },
    { id: 2, name: "محمد", role: "موظف", groupId: null, status: "active" }
  ]);
  const [newEmployeeName, setNewEmployeeName] = useState("");
  
  // المربع 4: المنيو
  const [menuCategories, setMenuCategories] = useState([
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", products: [
      { id: 101, name: "شيشة تفاح", price: 15 },
      { id: 102, name: "شيشة عنب", price: 15 },
      { id: 103, name: "شيشة نعناع", price: 15 }
    ] },
    { id: 2, name: "أطباق", icon: "🍔", color: "#4ecdc4", products: [
      { id: 201, name: "برجر", price: 12 },
      { id: 202, name: "بيتزا", price: 18 }
    ] },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", products: [
      { id: 301, name: "كوكا كولا", price: 3 },
      { id: 302, name: "عصير برتقال", price: 5 }
    ] },
    { id: 4, name: "حلويات", icon: "🍰", color: "#f9ca24", products: [
      { id: 401, name: "كعكة", price: 7 },
      { id: 402, name: "آيس كريم", price: 5 }
    ] }
  ]);
  
  const [showAddProductModal, setShowAddProductModal] = useState(false);
  const [showDeleteProductModal, setShowDeleteProductModal] = useState(false);
  const [showEditPriceModal, setShowEditPriceModal] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [newProduct, setNewProduct] = useState({ name: "", price: 0 });
  
  // المربع 5: كرت المطعم
  const [restaurantCard, setRestaurantCard] = useState({
    name: "مطعم الأندلس",
    location: "الجزائر العاصمة",
    description: "أشهى المأكولات العربية والعالمية في أجواء عائلية رائعة",
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
    phone: "+213 5 55 55 55 55",
    email: "info@andalus-restaurant.dz"
  });
  const [showEditRestaurantModal, setShowEditRestaurantModal] = useState(false);
  const [tempRestaurantCard, setTempRestaurantCard] = useState({ ...restaurantCard });
  
  // المربع 6: الفواتير
  const [invoices, setInvoices] = useState([]);
  const [filterType, setFilterType] = useState("daily");
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [selectedSeason, setSelectedSeason] = useState("spring");
  
  // ==================== FUNCTIONS ====================
  
  // المربع 1: إدارة الطاولات
  const addTables = () => {
    const startId = tables.length + 1;
    const newTables = [];
    for (let i = 0; i < newTableCount; i++) {
      const tableId = startId + i;
      newTables.push({
        id: tableId,
        number: tableId,
        groupId: selectedGroupForTable || null,
        status: "free"
      });
    }
    setTables([...tables, ...newTables]);
    alert(`✅ تم إضافة ${newTableCount} طاولة جديدة بنجاح!`);
  };
  
  const showQRPlaceholderFunc = (table) => {
    setSelectedTableForQR(table);
    setShowQRPlaceholder(true);
  };
  
  // المربع 2: إدارة المجموعات
  const addGroup = () => {
    if (!newGroupName.trim()) {
      alert("⚠️ الرجاء إدخال اسم المجموعة");
      return;
    }
    const newGroup = {
      id: groups.length + 1,
      name: newGroupName,
      tableIds: [],
      tableRange: { start: null, end: null }
    };
    setGroups([...groups, newGroup]);
    setNewGroupName("");
    alert(`✅ تم إضافة المجموعة "${newGroupName}" بنجاح`);
  };
  
  const assignTablesToGroup = (groupId, startTable, endTable) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const tableIds = [];
        for (let i = startTable; i <= endTable; i++) {
          if (tables.find(t => t.number === i)) {
            tableIds.push(i);
          }
        }
        return {
          ...group,
          tableIds,
          tableRange: { start: startTable, end: endTable }
        };
      }
      return group;
    });
    setGroups(updatedGroups);
    
    const updatedTables = tables.map(table => {
      if (table.number >= startTable && table.number <= endTable) {
        return { ...table, groupId };
      }
      return table;
    });
    setTables(updatedTables);
    
    alert(`✅ تم تعيين الطاولات ${startTable} إلى ${endTable} للمجموعة ${groupId}`);
  };
  
  // المربع 3: ربط الموظفين
  const addEmployee = () => {
    if (!newEmployeeName.trim()) {
      alert("⚠️ الرجاء إدخال اسم الموظف");
      return;
    }
    const newEmployee = {
      id: employees.length + 1,
      name: newEmployeeName,
      role: "موظف",
      groupId: null,
      status: "active"
    };
    setEmployees([...employees, newEmployee]);
    setNewEmployeeName("");
    alert(`✅ تم إضافة الموظف "${newEmployeeName}" بنجاح`);
  };
  
  const assignEmployeeToGroup = (employeeId, groupId) => {
    const updatedEmployees = employees.map(emp => {
      if (emp.id === employeeId) {
        return { ...emp, groupId };
      }
      return emp;
    });
    setEmployees(updatedEmployees);
    
    const employee = employees.find(e => e.id === employeeId);
    const group = groups.find(g => g.id === groupId);
    alert(`✅ تم ربط ${employee?.name} بالمجموعة ${group?.name}`);
  };
  
  // المربع 4: تعديل المنيو
  const addProduct = () => {
    if (!newProduct.name || newProduct.price <= 0) {
      alert("⚠️ الرجاء إدخال اسم المنتج وسعر صحيح");
      return;
    }
    
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === selectedCategory) {
        const newId = Math.max(...cat.products.map(p => p.id), 0) + 1;
        return {
          ...cat,
          products: [...cat.products, { ...newProduct, id: newId }]
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    setShowAddProductModal(false);
    setNewProduct({ name: "", price: 0 });
    alert(`✅ تم إضافة المنتج "${newProduct.name}" بنجاح`);
  };
  
  const deleteProduct = (categoryId, productId) => {
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === categoryId) {
        return {
          ...cat,
          products: cat.products.filter(p => p.id !== productId)
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    alert(`✅ تم حذف المنتج بنجاح`);
  };
  
  const updateProductPrice = (categoryId, productId, newPrice) => {
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === categoryId) {
        return {
          ...cat,
          products: cat.products.map(p => 
            p.id === productId ? { ...p, price: newPrice } : p
          )
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    alert(`✅ تم تحديث السعر بنجاح`);
  };
  
  // المربع 5: كرت المطعم
  const updateRestaurantCard = () => {
    setRestaurantCard({ ...tempRestaurantCard });
    setShowEditRestaurantModal(false);
    alert(`✅ تم تحديث كرت المطعم بنجاح`);
  };
  
  // المربع 6: الفواتير
  const generateInvoice = () => {
    const mockInvoices = [];
    
    if (filterType === "daily") {
      for (let i = 1; i <= 10; i++) {
        mockInvoices.push({
          id: i,
          tableNumber: i,
          groupId: i <= 5 ? 1 : 2,
          total: Math.floor(Math.random() * 500 + 100),
          items: Math.floor(Math.random() * 5 + 1),
          date: selectedDate,
          time: `${Math.floor(Math.random() * 12 + 10)}:${Math.floor(Math.random() * 60)}`
        });
      }
    } else if (filterType === "monthly") {
      for (let i = 1; i <= 30; i++) {
        mockInvoices.push({
          id: i,
          tableNumber: Math.floor(Math.random() * 20 + 1),
          total: Math.floor(Math.random() * 2000 + 500),
          items: Math.floor(Math.random() * 15 + 3),
          date: `${selectedYear}-${String(selectedMonth + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`
        });
      }
    } else {
      const months = selectedSeason === "spring" ? [2, 3, 4] : selectedSeason === "summer" ? [5, 6, 7] : selectedSeason === "autumn" ? [8, 9, 10] : [11, 0, 1];
      for (let i = 1; i <= 90; i++) {
        mockInvoices.push({
          id: i,
          tableNumber: Math.floor(Math.random() * 20 + 1),
          total: Math.floor(Math.random() * 3000 + 1000),
          items: Math.floor(Math.random() * 20 + 5),
          date: `${selectedYear}-${String(months[Math.floor(Math.random() * months.length)] + 1).padStart(2, '0')}-${String(Math.floor(Math.random() * 28) + 1).padStart(2, '0')}`
        });
      }
    }
    
    setInvoices(mockInvoices);
  };
  
  const getTotalRevenue = () => {
    return invoices.reduce((sum, inv) => sum + inv.total, 0);
  };
  
  // ==================== STYLES ====================
  const style = `
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    .manager-container {
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b);
      min-height: 100vh;
      padding-top: 80px;
    }
    
    .manager-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 30px;
      max-width: 1400px;
      margin: 0 auto;
      padding: 20px;
    }
    
    .manager-card {
      background: rgba(255, 255, 255, 0.1);
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 25px;
      transition: all 0.3s ease;
      border: 1px solid rgba(34, 197, 94, 0.3);
      animation: fadeIn 0.5s ease-out;
    }
    
    .manager-card:hover {
      transform: translateY(-5px);
      box-shadow: 0 10px 40px rgba(0,0,0,0.3);
      border-color: rgba(34, 197, 94, 0.6);
    }
    
    .card-title {
      font-size: 1.8rem;
      font-weight: bold;
      color: white;
      margin-bottom: 20px;
      display: flex;
      align-items: center;
      gap: 10px;
      border-bottom: 2px solid #22c55e;
      padding-bottom: 10px;
    }
    
    .input-group {
      margin-bottom: 15px;
    }
    
    .input-group label {
      display: block;
      color: rgba(255,255,255,0.8);
      margin-bottom: 5px;
      font-size: 0.9rem;
    }
    
    .input-group input, .input-group select, .input-group textarea {
      width: 100%;
      padding: 10px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
      font-size: 0.9rem;
      transition: all 0.2s;
    }
    
    .input-group input:focus, .input-group select:focus, .input-group textarea:focus {
      outline: none;
      border-color: #22c55e;
      box-shadow: 0 0 10px rgba(34,197,94,0.3);
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
      margin-top: 10px;
    }
    
    .btn-primary:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .btn-secondary {
      background: linear-gradient(135deg, #3b82f6, #1d4ed8);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-secondary:hover {
      transform: scale(1.02);
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-danger:hover {
      transform: scale(1.02);
    }
    
    .table-list, .group-list, .employee-list {
      max-height: 300px;
      overflow-y: auto;
      margin-top: 15px;
    }
    
    .table-item, .group-item, .employee-item {
      background: rgba(255,255,255,0.08);
      padding: 10px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .qr-placeholder-btn {
      background: #22c55e;
      border: none;
      padding: 5px 12px;
      border-radius: 15px;
      color: white;
      cursor: pointer;
      font-size: 0.8rem;
    }
    
    .product-item {
      background: rgba(255,255,255,0.08);
      padding: 12px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .invoice-stats {
      background: linear-gradient(135deg, #22c55e, #15803d);
      padding: 20px;
      border-radius: 20px;
      text-align: center;
      margin-bottom: 20px;
    }
    
    .invoice-stats h3 {
      color: white;
      font-size: 2rem;
      margin: 0;
    }
    
    .invoice-item {
      background: rgba(255,255,255,0.08);
      padding: 12px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.9);
      backdrop-filter: blur(10px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 500px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    
    .qr-placeholder-box {
      background: rgba(0,0,0,0.5);
      border: 2px dashed #22c55e;
      border-radius: 20px;
      padding: 40px;
      text-align: center;
      margin: 20px 0;
    }
    
    @media (max-width: 768px) {
      .manager-grid {
        grid-template-columns: 1fr;
        gap: 20px;
        padding: 15px;
      }
      
      .card-title {
        font-size: 1.4rem;
      }
    }
  `;
  
  // ==================== RENDER ====================
  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="manager-container">
        <div className="manager-grid">
          
          {/* ========== المربع 1: إدارة الطاولات ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>🍽️</span> إدارة الطاولات
            </div>
            
            <div className="input-group">
              <label>عدد الطاولات الجديدة:</label>
              <input 
                type="number" 
                min="1" 
                max="50"
                value={newTableCount}
                onChange={(e) => setNewTableCount(parseInt(e.target.value))}
              />
            </div>
            
            <div className="input-group">
              <label>انتماء للمجموعة (اختياري):</label>
              <select value={selectedGroupForTable} onChange={(e) => setSelectedGroupForTable(e.target.value)}>
                <option value="">بدون مجموعة</option>
                {groups.map(g => (
                  <option key={g.id} value={g.id}>المجموعة {g.id}: {g.name}</option>
                ))}
              </select>
            </div>
            
            <button className="btn-primary" onClick={addTables}>
              ➕ إضافة طاولات
            </button>
            
            <div className="table-list">
              <h4 style={{ color: 'white', marginBottom: '10px' }}>الطاولات الحالية ({tables.length})</h4>
              {tables.map(table => (
                <div key={table.id} className="table-item">
                  <span style={{ color: 'white' }}>طاولة {table.number}</span>
                  <button className="qr-placeholder-btn" onClick={() => showQRPlaceholderFunc(table)}>
                    📱 كود QR
                  </button>
                </div>
              ))}
              {tables.length === 0 && (
                <p style={{ color: 'rgba(255,255,255,0.5)', textAlign: 'center' }}>لا توجد طاولات بعد</p>
              )}
            </div>
          </div>
          
          {/* ========== المربع 2: إدارة المجموعات ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>👥</span> إدارة المجموعات
            </div>
            
            <div className="input-group">
              <label>اسم المجموعة الجديدة:</label>
              <input 
                type="text"
                value={newGroupName}
                onChange={(e) => setNewGroupName(e.target.value)}
                placeholder="مثال: المجموعة أ"
              />
            </div>
            
            <button className="btn-primary" onClick={addGroup}>
              ➕ إضافة مجموعة
            </button>
            
            <div className="group-list">
              <h4 style={{ color: 'white', marginBottom: '10px' }}>المجموعات الحالية ({groups.length})</h4>
              {groups.map(group => (
                <div key={group.id} className="group-item">
                  <div>
                    <span style={{ color: 'white', fontWeight: 'bold' }}>{group.name}</span>
                    {group.tableRange.start && (
                      <div style={{ fontSize: '0.8rem', color: '#22c55e' }}>
                        طاولات: {group.tableRange.start} → {group.tableRange.end}
                      </div>
                    )}
                  </div>
                  <button 
                    className="btn-secondary" 
                    style={{ padding: '5px 10px', fontSize: '0.8rem' }}
                    onClick={() => {
                      const start = prompt("رقم بداية الطاولات:");
                      const end = prompt("رقم نهاية الطاولات:");
                      if (start && end) assignTablesToGroup(group.id, parseInt(start), parseInt(end));
                    }}
                  >
                    🪑 تعيين طاولات
                  </button>
                </div>
              ))}
            </div>
          </div>
          
          {/* ========== المربع 3: ربط الموظفين بالمجموعات ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>👨‍🍳</span> ربط الموظفين بالمجموعات
            </div>
            
            <div className="input-group">
              <label>اسم الموظف الجديد:</label>
              <input 
                type="text"
                value={newEmployeeName}
                onChange={(e) => setNewEmployeeName(e.target.value)}
                placeholder="مثال: أحمد"
              />
            </div>
            
            <button className="btn-primary" onClick={addEmployee}>
              ➕ إضافة موظف
            </button>
            
            <div className="employee-list">
              <h4 style={{ color: 'white', marginBottom: '10px' }}>الموظفين ({employees.length})</h4>
              {employees.map(emp => (
                <div key={emp.id} className="employee-item">
                  <div>
                    <span style={{ color: 'white', fontWeight: 'bold' }}>{emp.name}</span>
                    {emp.groupId && (
                      <div style={{ fontSize: '0.8rem', color: '#22c55e' }}>
                        → {groups.find(g => g.id === emp.groupId)?.name}
                      </div>
                    )}
                  </div>
                  <select 
                    value={emp.groupId || ""}
                    onChange={(e) => assignEmployeeToGroup(emp.id, parseInt(e.target.value))}
                    style={{
                      background: 'rgba(34,197,94,0.2)',
                      border: '1px solid #22c55e',
                      borderRadius: '10px',
                      padding: '5px',
                      color: 'white'
                    }}
                  >
                    <option value="">بدون مجموعة</option>
                    {groups.map(g => (
                      <option key={g.id} value={g.id}>{g.name}</option>
                    ))}
                  </select>
                </div>
              ))}
            </div>
          </div>
          
          {/* ========== المربع 4: تعديل المنيو ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>📝</span> تعديل المنيو
            </div>
            
            <div style={{ display: 'flex', gap: '10px', marginBottom: '20px', flexWrap: 'wrap' }}>
              <button className="btn-primary" onClick={() => setShowAddProductModal(true)}>
                ➕ إضافة منتج
              </button>
              <button className="btn-secondary" onClick={() => setShowDeleteProductModal(true)}>
                🗑️ حذف منتج
              </button>
              <button className="btn-secondary" onClick={() => setShowEditPriceModal(true)}>
                💰 تعديل السعر
              </button>
            </div>
            
            <div>
              <h4 style={{ color: 'white', marginBottom: '10px' }}>معاينة المنيو</h4>
              {menuCategories.map(cat => (
                <div key={cat.id} style={{ marginBottom: '15px' }}>
                  <h5 style={{ color: cat.color, marginBottom: '5px' }}>{cat.icon} {cat.name}</h5>
                  <div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.6)' }}>
                    {cat.products.map(p => `${p.name} (${p.price} DA)`).join(' • ')}
                  </div>
                </div>
              ))}
            </div>
          </div>
          
          {/* ========== المربع 5: كرت المطعم ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>🏪</span> كرت المطعم
            </div>
            
            <div style={{ textAlign: 'center', marginBottom: '20px' }}>
              <img 
                src={restaurantCard.logo} 
                alt="logo" 
                style={{ width: '80px', height: '80px', marginBottom: '10px', borderRadius: '50%' }}
              />
              <h3 style={{ color: '#22c55e', marginBottom: '5px' }}>{restaurantCard.name}</h3>
              <p style={{ color: 'rgba(255,255,255,0.7)' }}>📍 {restaurantCard.location}</p>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.9rem' }}>{restaurantCard.description}</p>
              <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem' }}>📞 {restaurantCard.phone}</p>
              <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem' }}>✉️ {restaurantCard.email}</p>
            </div>
            
            <button className="btn-primary" onClick={() => {
              setTempRestaurantCard({ ...restaurantCard });
              setShowEditRestaurantModal(true);
            }}>
              ✏️ تعديل الكرت
            </button>
          </div>
          
          {/* ========== المربع 6: الفواتير ========== */}
          <div className="manager-card">
            <div className="card-title">
              <span>📊</span> الفواتير
            </div>
            
            <div className="input-group">
              <label>نوع الفاتورة:</label>
              <select value={filterType} onChange={(e) => setFilterType(e.target.value)}>
                <option value="daily">📅 يومية</option>
                <option value="monthly">📆 شهرية</option>
                <option value="seasonal">🌿 موسمية</option>
              </select>
            </div>
            
            {filterType === "daily" && (
              <div className="input-group">
                <label>التاريخ:</label>
                <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} />
              </div>
            )}
            
            {filterType === "monthly" && (
              <div style={{ display: 'flex', gap: '10px' }}>
                <div className="input-group" style={{ flex: 1 }}>
                  <label>الشهر:</label>
                  <select value={selectedMonth} onChange={(e) => setSelectedMonth(parseInt(e.target.value))}>
                    {["جانفي", "فيفري", "مارس", "أفريل", "ماي", "جوان", "جويلية", "أوت", "سبتمبر", "أكتوبر", "نوفمبر", "ديسمبر"].map((m, i) => (
                      <option key={i} value={i}>{m}</option>
                    ))}
                  </select>
                </div>
                <div className="input-group" style={{ flex: 1 }}>
                  <label>السنة:</label>
                  <input type="number" value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} />
                </div>
              </div>
            )}
            
            {filterType === "seasonal" && (
              <div style={{ display: 'flex', gap: '10px' }}>
                <div className="input-group" style={{ flex: 1 }}>
                  <label>الموسم:</label>
                  <select value={selectedSeason} onChange={(e) => setSelectedSeason(e.target.value)}>
                    <option value="spring">🌸 الربيع (مارس-ماي)</option>
                    <option value="summer">☀️ الصيف (جوان-أوت)</option>
                    <option value="autumn">🍂 الخريف (سبتمبر-نوفمبر)</option>
                    <option value="winter">❄️ الشتاء (ديسمبر-فيفري)</option>
                  </select>
                </div>
                <div className="input-group" style={{ flex: 1 }}>
                  <label>السنة:</label>
                  <input type="number" value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} />
                </div>
              </div>
            )}
            
            <button className="btn-primary" onClick={generateInvoice}>
              🔍 عرض الفواتير
            </button>
            
            {invoices.length > 0 && (
              <>
                <div className="invoice-stats">
                  <h3>{getTotalRevenue()} DA</h3>
                  <p style={{ color: 'rgba(255,255,255,0.8)' }}>إجمالي الإيرادات</p>
                  <p style={{ fontSize: '0.8rem' }}>{invoices.length} فاتورة</p>
                </div>
                
                <div className="table-list" style={{ maxHeight: '250px' }}>
                  {invoices.slice(0, 10).map(inv => (
                    <div key={inv.id} className="invoice-item">
                      <span style={{ color: 'white' }}>طاولة {inv.tableNumber}</span>
                      <span style={{ color: '#22c55e', fontWeight: 'bold' }}>{inv.total} DA</span>
                    </div>
                  ))}
                  {invoices.length > 10 && (
                    <p style={{ color: 'rgba(255,255,255,0.5)', textAlign: 'center', fontSize: '0.8rem' }}>
                      ... و {invoices.length - 10} فواتير أخرى
                    </p>
                  )}
                </div>
              </>
            )}
          </div>
          
        </div>
      </div>
      
      {/* ========== MODALS ========== */}
      
      {/* مودال مكان QR Code (placeholder) */}
      {showQRPlaceholder && selectedTableForQR && (
        <div className="modal-overlay" onClick={() => setShowQRPlaceholder(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', textAlign: 'center', marginBottom: '20px' }}>📱 كود QR للطاولة {selectedTableForQR.number}</h2>
            
            <div className="qr-placeholder-box">
              <div style={{ fontSize: '4rem', marginBottom: '10px' }}>📱</div>
              <p style={{ color: '#22c55e', fontWeight: 'bold', marginBottom: '10px' }}>مكان كود QR</p>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>
                الطاولة رقم {selectedTableForQR.number}
              </p>
              <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', marginTop: '10px' }}>
                سيتم إضافة كود QR الحقيقي لاحقاً
              </p>
            </div>
            
            <p style={{ color: 'rgba(255,255,255,0.7)', textAlign: 'center', marginBottom: '20px' }}>
              يمكن للعميل مسح هذا الكود للوصول إلى المنيو
            </p>
            
            <button className="btn-primary" style={{ width: '100%' }} onClick={() => setShowQRPlaceholder(false)}>
              إغلاق
            </button>
          </div>
        </div>
      )}
      
      {/* مودال إضافة منتج */}
      {showAddProductModal && (
        <div className="modal-overlay" onClick={() => setShowAddProductModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>➕ إضافة منتج جديد</h2>
            <div className="input-group">
              <label>القسم:</label>
              <select onChange={(e) => setSelectedCategory(parseInt(e.target.value))}>
                <option value="">اختر القسم</option>
                {menuCategories.map(cat => (
                  <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                ))}
              </select>
            </div>
            <div className="input-group">
              <label>اسم المنتج:</label>
              <input type="text" value={newProduct.name} onChange={(e) => setNewProduct({...newProduct, name: e.target.value})} />
            </div>
            <div className="input-group">
              <label>السعر (DA):</label>
              <input type="number" value={newProduct.price} onChange={(e) => setNewProduct({...newProduct, price: parseFloat(e.target.value)})} />
            </div>
            <button className="btn-primary" style={{ width: '100%' }} onClick={addProduct}>
              💾 حفظ المنتج
            </button>
          </div>
        </div>
      )}
      
      {/* مودال حذف منتج */}
      {showDeleteProductModal && (
        <div className="modal-overlay" onClick={() => setShowDeleteProductModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>🗑️ حذف منتج</h2>
            {menuCategories.map(cat => (
              <div key={cat.id} style={{ marginBottom: '20px' }}>
                <h3 style={{ color: cat.color }}>{cat.icon} {cat.name}</h3>
                {cat.products.map(product => (
                  <div key={product.id} className="product-item">
                    <span style={{ color: 'white' }}>{product.name}</span>
                    <button className="btn-danger" onClick={() => deleteProduct(cat.id, product.id)}>
                      حذف
                    </button>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* مودال تعديل السعر */}
      {showEditPriceModal && (
        <div className="modal-overlay" onClick={() => setShowEditPriceModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>💰 تعديل السعر</h2>
            {menuCategories.map(cat => (
              <div key={cat.id} style={{ marginBottom: '20px' }}>
                <h3 style={{ color: cat.color }}>{cat.icon} {cat.name}</h3>
                {cat.products.map(product => (
                  <div key={product.id} className="product-item">
                    <span style={{ color: 'white' }}>{product.name}</span>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                      <span style={{ color: '#22c55e' }}>{product.price} DA</span>
                      <button 
                        className="btn-secondary" 
                        onClick={() => {
                          const newPrice = prompt("السعر الجديد:", product.price);
                          if (newPrice) updateProductPrice(cat.id, product.id, parseFloat(newPrice));
                        }}
                      >
                        تعديل
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* مودال تعديل كرت المطعم */}
      {showEditRestaurantModal && (
        <div className="modal-overlay" onClick={() => setShowEditRestaurantModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>✏️ تعديل كرت المطعم</h2>
            <div className="input-group">
              <label>اسم المطعم:</label>
              <input type="text" value={tempRestaurantCard.name} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, name: e.target.value})} />
            </div>
            <div className="input-group">
              <label>الموقع:</label>
              <input type="text" value={tempRestaurantCard.location} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, location: e.target.value})} />
            </div>
            <div className="input-group">
              <label>الوصف:</label>
              <textarea rows="3" value={tempRestaurantCard.description} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, description: e.target.value})} />
            </div>
            <div className="input-group">
              <label>رقم الهاتف:</label>
              <input type="text" value={tempRestaurantCard.phone} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, phone: e.target.value})} />
            </div>
            <div className="input-group">
              <label>البريد الإلكتروني:</label>
              <input type="email" value={tempRestaurantCard.email} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, email: e.target.value})} />
            </div>
            <div className="input-group">
              <label>رابط الشعار:</label>
              <input type="text" value={tempRestaurantCard.logo} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, logo: e.target.value})} />
            </div>
            <button className="btn-primary" style={{ width: '100%' }} onClick={updateRestaurantCard}>
              💾 حفظ التغييرات
            </button>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
